// Extract engagement event data
const eventData = $input.first().json;
const userId = eventData.user_id;
const eventType = eventData.event_type;
const engagementData = eventData.data;

let engagementAction = '';
let motivationMessage = '';
let actionPriority = 'normal';
let recommendedInterventions = [];

if (eventType === 'user.inactive') {
  const inactiveDays = engagementData.inactivity_days || 0;

  if (inactiveDays >= 14) {
    engagementAction = 'critical_re_engagement';
    motivationMessage = 'We miss you! Your art journey is waiting. Let\'s make today the day you come back to creating! 🎨✨';
    actionPriority = 'high';
    recommendedInterventions = ['personal_outreach', 'special_offer', 'easy_comeback_lesson', 'motivational_video'];
  } else if (inactiveDays >= 7) {
    engagementAction = 'moderate_re_engagement';
    motivationMessage = 'Your creativity is calling! How about a quick 10-minute art session to get back in the flow? 🌟';
    actionPriority = 'medium';
    recommendedInterventions = ['gentle_reminder', 'quick_practice', 'inspiration_content'];
  } else {
    engagementAction = 'gentle_re_engagement';
    motivationMessage = 'Ready to continue your artistic adventure? Let\'s pick up where you left off! 🎭';
    recommendedInterventions = ['friendly_nudge', 'progress_reminder'];
  }
} else if (eventType === 'streak.achieved') {
  const streakLength = engagementData.streak_length || 0;
  const streakLevel = engagementData.achievement_level || 'bronze';

  engagementAction = 'celebrate_streak';
  actionPriority = 'high';

  if (streakLength >= 30) {
    motivationMessage = `🔥 INCREDIBLE! ${streakLength} days of artistic dedication! You're a true master of consistency! Keep this legendary streak alive!`;
    recommendedInterventions = ['legendary_reward', 'community_showcase', 'exclusive_content', 'mastery_badge'];
  } else if (streakLength >= 14) {
    motivationMessage = `🌟 Amazing ${streakLength}-day streak! You're building incredible artistic discipline. This is the path to mastery!`;
    recommendedInterventions = ['streak_celebration', 'bonus_content', 'achievement_share', 'community_recognition'];
  } else if (streakLength >= 7) {
    motivationMessage = `🎉 Fantastic! One week of consistent practice! You're developing a powerful creative habit!`;
    recommendedInterventions = ['week_celebration', 'progress_highlight', 'bonus_points'];
  } else {
    motivationMessage = `✨ Great start! ${streakLength} days in a row! Keep this momentum going – consistency is key to artistic growth!`;
    recommendedInterventions = ['encouragement', 'streak_tips', 'next_goal_setting'];
  }
}

return [{
  json: {
    user_id: userId,
    event_type: eventType,
    engagement_action: engagementAction,
    action_priority: actionPriority,
    motivation_message: motivationMessage,
    recommended_interventions: recommendedInterventions,
    engagement_data: engagementData,
    processing_timestamp: new Date().toISOString()
  }
}];

