// Schedule appropriate follow-up based on engagement action
const engagementAction = $input.first().json.engagement_action;
const eventType = $input.first().json.event_type;
const userId = $input.first().json.user_id;

let followUpSchedule = [];

if (eventType === 'user.inactive') {
  const inactiveDays = $input.first().json.engagement_data.inactivity_days;

  if (inactiveDays >= 14) {
    // Critical - multiple touchpoints
    followUpSchedule = [
      { days: 1, type: 'check_in', message: 'Hope you\'re ready to dive back into your art! Any questions?' },
      { days: 3, type: 'encouragement', message: 'Small steps count! Even 5 minutes of practice makes a difference.' },
      { days: 7, type: 'personal_support', message: 'How can we better support your learning journey?' }
    ];
  } else if (inactiveDays >= 7) {
    // Moderate - gentle follow-up
    followUpSchedule = [
      { days: 2, type: 'gentle_reminder', message: 'Your art supplies are missing you! Ready for a creative session?' },
      { days: 5, type: 'inspiration', message: 'Check out this inspiring artwork from our community!' }
    ];
  } else {
    // Light touch
    followUpSchedule = [
      { days: 3, type: 'friendly_check', message: 'How\'s your artistic journey going? We\'re here to help!' }
    ];
  }
} else if (eventType === 'streak.achieved') {
  const streakLength = $input.first().json.engagement_data.streak_length;

  if (streakLength >= 30) {
    // Legendary status - special recognition
    followUpSchedule = [
      { days: 1, type: 'community_feature', message: 'Your dedication inspires others! Check out your community spotlight.' },
      { days: 7, type: 'mastery_check', message: 'Ready for an advanced challenge? Your skills have grown tremendously!' }
    ];
  } else if (streakLength >= 7) {
    followUpSchedule = [
      { days: 1, type: 'momentum_boost', message: 'Your consistency is paying off! Keep the amazing streak going!' },
      { days: 3, type: 'next_milestone', message: 'You\'re getting close to the next milestone. You\'ve got this!' }
    ];
  }
}

return [{
  json: {
    user_id: userId,
    engagement_action: engagementAction,
    follow_up_schedule: followUpSchedule,
    total_follow_ups: followUpSchedule.length,
    engagement_plan_created: true,
    created_at: new Date().toISOString()
  }
}];

